const rawText = $input.first().json.text || '';
const fileName = $input.first().json.fileName || 'unknown.pdf';
// Truncate if too long
const truncated = rawText.length > 30000 ? rawText.substring(0, 30000) + '\n[TRUNCATED]' : rawText;

return [{
  json: { paper_text: truncated, file_name: fileName }
}];

// Parse and validate the LLM output
const rawOutput = $input.first().json.output || $input.first().json.text || '';

// Try to extract JSON from the output
let parsed;
try {
  // Remove markdown fences if present
  let cleaned = rawOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Try to find JSON in the text
  const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      return [{ json: { error: 'Failed to parse LLM output as JSON', raw_output: rawOutput } }];
    }
  } else {
    return [{ json: { error: 'No JSON found in LLM output', raw_output: rawOutput } }];
  }
}

// Validate required fields
const requiredFields = ['paper_id', 'title', 'authors', 'year', 'research_objective', 'methodology', 'key_findings'];
const missingFields = requiredFields.filter(f => !parsed[f]);

if (missingFields.length > 0) {
  parsed.extraction_notes = (parsed.extraction_notes || '') + ` WARNING: Missing fields: ${missingFields.join(', ')}`;
  parsed.extraction_confidence = 'LOW';
}

return [{ json: { extracted_paper: parsed } }];

const items = $input.all();
const extracted = [];
for (const item of items) {
  if (item.json.extracted_paper) {
    extracted.push(item.json.extracted_paper);
  }
}
return [{ json: { extracted_papers: extracted } }];

// The input is { extracted_papers: [...] } from the collect node
const data = $input.first().json;
return [{
  json: { "success": true },
  binary: {
    json_data: {
      data: Buffer.from(JSON.stringify(data, null, 2)).toString('base64'),
      mimeType: 'application/json',
      fileName: 'temp_extracted.json'
    }
  }
}];

